package com.example.usersapp.net;

import java.util.concurrent.TimeUnit;

import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public final class ApiClient {
    private static volatile UsersApi usersApi;

    private ApiClient() {}

    public static UsersApi usersApi() {
        if (usersApi == null) {
            synchronized (ApiClient.class) {
                if (usersApi == null) {
                    OkHttpClient.Builder okBuilder = new OkHttpClient.Builder()
                            .connectTimeout(15, TimeUnit.SECONDS)
                            .readTimeout(20, TimeUnit.SECONDS)
                            .writeTimeout(20, TimeUnit.SECONDS);

                    if (isDebug()) {
                        HttpLoggingInterceptor logging = new HttpLoggingInterceptor();
                        logging.setLevel(HttpLoggingInterceptor.Level.BODY);
                        okBuilder.addInterceptor(logging);
                    }

                    Retrofit retrofit = new Retrofit.Builder()
                            .baseUrl(EnvConfig.baseUrl())
                            .client(okBuilder.build())
                            .addConverterFactory(GsonConverterFactory.create())
                            .build();

                    usersApi = retrofit.create(UsersApi.class);
                }
            }
        }
        return usersApi;
    }

    private static boolean isDebug() {
        try {
            Class<?> buildConfig = Class.forName("com.example.usersapp.BuildConfig");
            return buildConfig.getField("DEBUG").getBoolean(null);
        } catch (Throwable t) {
            return false;
        }
    }
}

