package com.example.usersapp.data;

import com.example.usersapp.net.ApiClient;
import com.example.usersapp.net.ApiModels;

import java.io.IOException;
import java.util.List;

import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public final class UsersRepository {

    public interface ResultCallback<T> {
        void onSuccess(T data);
        void onError(String message);
    }

    public void fetchUsers(final ResultCallback<List<ApiModels.User>> callback) {
        ApiClient.usersApi().getUsers().enqueue(new Callback<List<ApiModels.User>>() {
            @Override
            public void onResponse(Call<List<ApiModels.User>> call, Response<List<ApiModels.User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    callback.onSuccess(response.body());
                } else {
                    callback.onError("Request failed: HTTP " + response.code());
                }
            }

            @Override
            public void onFailure(Call<List<ApiModels.User>> call, Throwable t) {
                String msg = t.getMessage();
                if (t instanceof IOException) {
                    callback.onError("Network error" + (msg != null ? (": " + msg) : ""));
                } else {
                    callback.onError("Unexpected error" + (msg != null ? (": " + msg) : ""));
                }
            }
        });
    }
}

