package com.example.usersapp.ui;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;

import com.example.usersapp.R;
import com.example.usersapp.net.ApiModels;

import java.util.ArrayList;
import java.util.List;

public final class UsersAdapter extends RecyclerView.Adapter<UsersAdapter.VH> {

    private final List<ApiModels.User> items = new ArrayList<>();

    public void submit(List<ApiModels.User> users) {
        items.clear();
        if (users != null) items.addAll(users);
        notifyDataSetChanged();
    }

    @NonNull
    @Override
    public VH onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View v = LayoutInflater.from(parent.getContext()).inflate(R.layout.item_user, parent, false);
        return new VH(v);
    }

    @Override
    public void onBindViewHolder(@NonNull VH holder, int position) {
        ApiModels.User u = items.get(position);
        holder.name.setText(u.name != null ? u.name : "(no name)");
        holder.email.setText(u.email != null ? u.email : "");
    }

    @Override
    public int getItemCount() {
        return items.size();
    }

    static final class VH extends RecyclerView.ViewHolder {
        final TextView name;
        final TextView email;

        VH(@NonNull View itemView) {
            super(itemView);
            name = itemView.findViewById(R.id.name);
            email = itemView.findViewById(R.id.email);
        }
    }
}

// app/src/main/java/com/example/usersapp/MainActivity.java
package com.example.usersapp;

import android.os.Bundle;
import android.view.View;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.usersapp.data.UsersRepository;
import com.example.usersapp.net.ApiModels;
import com.example.usersapp.ui.UsersAdapter;
import com.google.android.material.appbar.MaterialToolbar;
import com.google.android.material.progressindicator.CircularProgressIndicator;

import java.util.List;

public final class MainActivity extends AppCompatActivity {

    private CircularProgressIndicator progress;
    private TextView errorText;
    private UsersAdapter adapter;
    private final UsersRepository repo = new UsersRepository();

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        MaterialToolbar toolbar = findViewById(R.id.toolbar);
        setSupportActionBar(toolbar);

        progress = findViewById(R.id.progress);
        errorText = findViewById(R.id.errorText);
        RecyclerView recycler = findViewById(R.id.recycler);

        adapter = new UsersAdapter();
        recycler.setLayoutManager(new LinearLayoutManager(this));
        recycler.setAdapter(adapter);

        load();
    }

    private void load() {
        showLoading(true);
        showError(null);

        repo.fetchUsers(new UsersRepository.ResultCallback<List<ApiModels.User>>() {
            @Override
            public void onSuccess(List<ApiModels.User> data) {
                showLoading(false);
                adapter.submit(data);
            }

            @Override
            public void onError(String message) {
                showLoading(false);
                showError(message != null ? message : "Error");
            }
        });
    }

    private void showLoading(boolean show) {
        progress.setVisibility(show ? View.VISIBLE : View.GONE);
    }

    private void showError(@Nullable String msg) {
        if (msg == null || msg.trim().isEmpty()) {
            errorText.setVisibility(View.GONE);
            errorText.setText("");
        } else {
            errorText.setVisibility(View.VISIBLE);
            errorText.setText(msg);
        }
    }
}

